sys_script_include.script:
/**
 * TableRecordDecorator
 *
 * Responsible for building and decorating record objects from GlideRecord data.
 * Handles column resolution, primary link building, and record transformation.
 *
 * @class
 */
var TableRecordDecorator = Class.create();
TableRecordDecorator.prototype = {
    initialize: function (params) {
        params = params || {};
        this.logger = params.logger;
        this.configObject = params.configObject || {};
        this.provider = params.provider;
    },

    /**
     * Build a base record object from a GlideRecord.
     *
     * @param {GlideRecord} glideRecord
     * @param {Array} columns
     * @return {Object}
     */
    buildBaseRecord: function (glideRecord, columns) {
        var record = {};

        for (var i = 0; i < columns.length; i++) {
            var column = columns[i] || {};
            var columnName = column.name;

            if (!columnName) {
                continue;
            }

            record[columnName] = this.resolveColumnValue(glideRecord, column);
        }

        record.sys_id = glideRecord.getUniqueValue();

        var rowClickAction =
            typeof this.provider.getRowClickAction === "function"
                ? this.provider.getRowClickAction()
                : {};
        var actionConfig = rowClickAction.action || {};
        var urlField = actionConfig.urlField || "_primaryLink";

        if (
            actionConfig.type === "link" &&
            urlField &&
            !record.hasOwnProperty(urlField)
        ) {
            record[urlField] = this.buildPrimaryLink(record);
        }

        return record;
    },

    /**
     * Resolve a column value from a GlideRecord.
     *
     * @param {GlideRecord} glideRecord
     * @param {Object} column
     * @return {string}
     */
    resolveColumnValue: function (glideRecord, column) {
        var sourceField = column.sourceField || column.name;
        var useDisplayValue = column.useDisplayValue !== false;
        var value = "";

        if (!sourceField) {
            return value;
        }

        if (useDisplayValue) {
            value = glideRecord.getDisplayValue(sourceField);
        } else {
            value = glideRecord.getValue(sourceField);

            // getValue does not reliably support dot-walk fields.
            if (value == null && sourceField.indexOf(".") !== -1) {
                value = glideRecord.getDisplayValue(sourceField);
            }
        }

        return value || "";
    },

    /**
     * Build the primary link for a record.
     *
     * @param {Object} record
     * @return {string}
     */
    buildPrimaryLink: function (record) {
        /* prettier-ignore */
        return ("?id=" + this.provider.getDetailViewPage() + "&scm_record_id=" + (record[this.provider.getIdField()] || ""));
    },

    /**
     * Decorate a record after initial build.
     * Override this method in subclasses for custom decoration.
     *
     * @param {Object} record
     * @param {GlideRecord} glideRecord
     * @return {Object}
     */
    decorateRecord: function (record, glideRecord) {
        if (
            !this.provider ||
            typeof this.provider.decorateRecord !== "function"
        ) {
            return record;
        }

        try {
            return this.provider.decorateRecord(record, glideRecord) || record;
        } catch (error) {
            if (this.logger) {
                this.logger.error({
                    method: "decorateRecord",
                    message: "Error in provider decorateRecord hook",
                    error: error.message,
                    providerType: this.provider.type,
                });
            }
        }

        return record;
    },

    type: "TableRecordDecorator",
};
